1	// COR24 APL Interpreter -- Parser
2	// Right-to-left recursive descent with vector literal stranding.
3	// APL: all operators equal precedence, right-associative.
4	// 2 + 3 * 4  ->  2 + (3 * 4)  ->  14
5	// 1 2 3      ->  3-element vector (adjacent numbers strand)
6	
7	#pragma once
8	
9	// AST node types
10	#define NODE_NUM    0   // integer literal (val = value)
11	#define NODE_BINOP  1   // binary op (val = operator tok type)
12	#define NODE_NEG    2   // monadic negate (right = operand)
13	#define NODE_IDENT  3   // variable reference (val = symbol index)
14	#define NODE_ASSIGN 4   // assignment (val = symbol index, right = expr)
15	#define NODE_VEC    5   // vector literal (val = heap array index)
16	#define NODE_MONAD  6   // monadic primitive (val = RES_xxx, right = operand)
17	#define NODE_DYAD   7   // dyadic primitive (val = RES_xxx, left/right = args)
18	#define NODE_REDUCE 8   // reduce operator (val = op tok type, right = operand)
19	#define NODE_QOUT   9   // quad output (right = expr to print)
20	
21	#define AST_MAX 64
22	
23	// AST storage (parallel arrays)
24	int node_type[AST_MAX];
25	int node_val[AST_MAX];
26	int node_left[AST_MAX];
27	int node_right[AST_MAX];
28	int node_count;
29	
30	// Parser state
31	int parse_pos;
32	int parse_err;
33	char *parse_line;   // source line for identifier lookup
34	
35	// Allocate a new AST node
36	int ast_new() {
37	    if (node_count >= AST_MAX) {
38	        parse_err = 1;
39	        return 0;
40	    }
41	    int n = node_count;
42	    node_count++;
43	    node_left[n] = -1;
44	    node_right[n] = -1;
45	    return n;
46	}
47	
48	int ast_num(int val) {
49	    int n = ast_new();
50	    node_type[n] = NODE_NUM;
51	    node_val[n] = val;
52	    return n;
53	}
54	
55	int ast_binop(int op, int left, int right) {
56	    int n = ast_new();
57	    node_type[n] = NODE_BINOP;
58	    node_val[n] = op;
59	    node_left[n] = left;
60	    node_right[n] = right;
61	    return n;
62	}
63	
64	int ast_neg(int operand) {
65	    int n = ast_new();
66	    node_type[n] = NODE_NEG;
67	    node_right[n] = operand;
68	    return n;
69	}
70	
71	int ast_ident(int sym_idx) {
72	    int n = ast_new();
73	    node_type[n] = NODE_IDENT;
74	    node_val[n] = sym_idx;
75	    return n;
76	}
77	
78	int ast_assign(int sym_idx, int expr) {
79	    int n = ast_new();
80	    node_type[n] = NODE_ASSIGN;
81	    node_val[n] = sym_idx;
82	    node_right[n] = expr;
83	    return n;
84	}
85	
86	int ast_vec(int heap_idx) {
87	    int n = ast_new();
88	    node_type[n] = NODE_VEC;
89	    node_val[n] = heap_idx;
90	    return n;
91	}
92	
93	int ast_monad(int res_id, int operand) {
94	    int n = ast_new();
95	    node_type[n] = NODE_MONAD;
96	    node_val[n] = res_id;
97	    node_right[n] = operand;
98	    return n;
99	}
100	
101	int ast_dyad(int res_id, int left, int right) {
102	    int n = ast_new();
103	    node_type[n] = NODE_DYAD;
104	    node_val[n] = res_id;
105	    node_left[n] = left;
106	    node_right[n] = right;
107	    return n;
108	}
109	
110	int ast_reduce(int op, int operand) {
111	    int n = ast_new();
112	    node_type[n] = NODE_REDUCE;
113	    node_val[n] = op;
114	    node_right[n] = operand;
115	    return n;
116	}
117	
118	// Check if a reserved word can be used dyadically
