6	#include <stdio.h>
7	
8	#define IO_LINE_MAX 120
9	
10	// Read a line from UART into buf (max len-1 chars + NUL).
11	// Handles backspace (BS=8, DEL=127): erases last char, sends BS-SPACE-BS.
12	// Returns number of chars read (excluding NUL), or 0 on empty line.
13	// Echoes characters as typed. Terminates on CR (13) or LF (10).
14	int io_getline(char *buf, int len) {
15	    int pos = 0;
16	    int maxpos = len - 1;
17	
18	    while (1) {
19	        int ch = getchar();
20	
21	        if (ch == 10 || ch == 13) {
22	            // Newline -- terminate
23	            putchar(10);
24	            buf[pos] = 0;
25	            return pos;
26	        }
27	
28	        if (ch == 8 || ch == 127) {
29	            // Backspace or DEL -- erase last char
30	            if (pos > 0) {
31	                pos--;
32	                putchar(8);   // BS
33	                putchar(32);  // space
34	                putchar(8);   // BS
35	            }
36	        } else if (ch >= 32 && pos < maxpos) {
37	            // Printable character
38	            buf[pos] = ch;
39	            pos++;
40	            putchar(ch);
41	        }
42	        // Ignore other control chars and overflow
43	    }
44	}
45	
46	// Print a string without trailing newline
47	void io_print(char *s) {
48	    while (*s) {
49	        putchar(*s);
50	        s = s + 1;
51	    }
